query:
SELECT 
  (SELECT COUNT(*) FROM evidences) as total_evidencias,
  (SELECT COUNT(*) FROM evidences e LEFT JOIN actions a ON e.actionId = a.id WHERE a.id IS NULL) as orfas_restantes;

